// Face-landmark template loader.
//
// Penelope's particle face is anchored to a 468-point 3D landmark cloud
// (MediaPipe FaceMesh schema). The points come from one of two sources:
//
//   1. assets/face-mesh.json    <-- PREFERRED. Generated by
//                                   python/extract_face_mesh.py from a
//                                   real Penelope Cruz reference photo
//                                   you supply in assets/reference/.
//                                   This is what the user actually wants:
//                                   the particles forming her actual face.
//
//   2. CANONICAL_FALLBACK       <-- A procedurally-generated reasonable
//                                   face-shaped template, used on first
//                                   launch before you've supplied a photo,
//                                   so something renders out of the box.
//
// The exported FACE_LANDMARKS array is filled in by app.js calling
// loadFaceLandmarks() before constructing PenelopeFace.

export let FACE_LANDMARKS = canonicalFallback();

export async function loadFaceLandmarks() {
  try {
    const b64 = await window.penelope.readAsset('assets/face-mesh.json');
    if (b64) {
      const json = JSON.parse(atob(b64));
      if (Array.isArray(json) && json.length >= 400 && json[0].length === 3) {
        FACE_LANDMARKS = normalize(json);
        return { source: 'user-photo', count: FACE_LANDMARKS.length };
      }
    }
  } catch (e) {
    console.warn('face-mesh.json missing, using fallback', e);
  }
  return { source: 'fallback', count: FACE_LANDMARKS.length };
}

function normalize(points) {
  // Re-center to origin, scale to fit roughly inside [-0.5, 0.5].
  let cx = 0, cy = 0, cz = 0;
  for (const [x, y, z] of points) { cx += x; cy += y; cz += z; }
  cx /= points.length; cy /= points.length; cz /= points.length;
  let max = 0;
  for (const [x, y, z] of points) {
    const d = Math.max(Math.abs(x - cx), Math.abs(y - cy));
    if (d > max) max = d;
  }
  const s = 0.5 / (max || 1);
  return points.map(([x, y, z]) => [
    (x - cx) * s,
    -(y - cy) * s,    // image-y is down; flip for 3D
    (z - cz) * s * 0.7,
  ]);
}

// Procedural reasonable face-shaped cloud used until extract_face_mesh.py
// has run on a real reference. ~468 points, FaceMesh-like coverage.
function canonicalFallback() {
  const pts = [];
  // Skull / face oval
  const ovalN = 60;
  for (let i = 0; i < ovalN; i++) {
    const t = (i / ovalN) * Math.PI * 2;
    const r = 0.42 + 0.04 * Math.sin(t * 2);
    const x = r * 0.78 * Math.cos(t);
    const y = r * Math.sin(t);
    const taper = y < 0 ? (1 + y * 0.5) : 1; // narrow chin
    pts.push([x * taper, y, 0.05 + 0.04 * Math.cos(t)]);
  }
  // Inner facial fill
  const fillN = 200;
  for (let i = 0; i < fillN; i++) {
    const a = Math.random() * Math.PI * 2;
    const r = Math.sqrt(Math.random()) * 0.36;
    const x = r * 0.78 * Math.cos(a);
    const y = r * Math.sin(a);
    pts.push([x, y, 0.12 + 0.06 * Math.cos(a)]);
  }
  // Jawline
  for (let i = 0; i < 22; i++) {
    const t = -1 + (i / 21) * 2; // -1 .. 1
    pts.push([0.32 * t, -0.32 - 0.08 * Math.cos(t * Math.PI / 2), 0.06]);
  }
  // Left eye ring
  const eyeRing = (cx, cy, idxBase) => {
    for (let i = 0; i < 16; i++) {
      const t = (i / 16) * Math.PI * 2;
      pts.push([
        cx + 0.06 * Math.cos(t),
        cy + 0.025 * Math.sin(t),
        0.12,
      ]);
    }
  };
  eyeRing(-0.13, 0.07);
  eyeRing(0.13, 0.07);
  // Brows
  for (let side of [-1, 1]) {
    for (let i = 0; i < 12; i++) {
      const t = i / 11;
      pts.push([side * (0.06 + t * 0.13), 0.14 + 0.015 * Math.sin(t * Math.PI), 0.13]);
    }
  }
  // Nose ridge + tip
  for (let i = 0; i < 14; i++) {
    const t = i / 13;
    pts.push([0, 0.08 - t * 0.18, 0.16 - t * 0.02]);
  }
  for (let i = 0; i < 12; i++) {
    const a = (i / 11) * Math.PI;
    pts.push([0.04 * Math.cos(a), -0.11, 0.13 + 0.02 * Math.sin(a)]);
  }
  // Lips: outer ring
  for (let i = 0; i < 22; i++) {
    const t = (i / 22) * Math.PI * 2;
    pts.push([0.09 * Math.cos(t), -0.20 + 0.025 * Math.sin(t), 0.13]);
  }
  // Lips: inner ring
  for (let i = 0; i < 14; i++) {
    const t = (i / 14) * Math.PI * 2;
    pts.push([0.06 * Math.cos(t), -0.20 + 0.012 * Math.sin(t), 0.135]);
  }
  // Cheeks
  for (let side of [-1, 1]) {
    for (let i = 0; i < 12; i++) {
      const x = side * (0.18 + Math.random() * 0.05);
      const y = -0.02 + (Math.random() - 0.5) * 0.08;
      pts.push([x, y, 0.10]);
    }
  }
  // Pad to ~468
  while (pts.length < 468) {
    pts.push([
      (Math.random() - 0.5) * 0.6,
      (Math.random() - 0.5) * 0.7,
      0.05 + Math.random() * 0.08,
    ]);
  }
  return pts;
}
